import React, { useState } from 'react';
import { Link } from 'react-router-dom';

const HeaderBar = () => {
  const [showMenu, setShowMenu] = useState(false);
  const [showCategory, setShowCategory] = useState(false);

  return (
    <header className="bg-[#fff1f3] text-[#4b2c2b] shadow-md">
      {/* --- Top bar giữ nguyên --- */}
      <div className="bg-[#f9e3e6] text-sm py-2 px-4 flex justify-between items-center">
        <div>🎀 Miễn phí giao hàng cho đơn từ 500k 🎀</div>
        <div>
          <Link to="/login" className="hover:underline mx-2">Đăng nhập</Link>
          |
          <Link to="/register" className="hover:underline mx-2">Đăng ký</Link>
        </div>
      </div>

      {/* --- Header chính + Navbar gộp chung --- */}
      <div className="flex items-center justify-between px-6 py-3">
        {/* Logo */}
        <Link to="/" className="text-2xl font-bold text-green-700">Flower Shop</Link>

        {/* Ô tìm kiếm */}
        <input 
          type="text"
          placeholder="Tìm kiếm hoa..."
          className="h-9 w-80 bg-white border border-green-300 rounded-full px-4 text-sm focus:outline-none focus:ring-2 focus:ring-green-400"
        />

        {/* Biểu tượng giỏ hàng */}
        <Link to="/cart" className="relative">
          <i className="fas fa-shopping-cart text-green-700 text-xl"></i>
        </Link>
      </div>

      {/* --- Navbar --- */}
      <nav 
        className="flex justify-center bg-[#f9e3e6] py-2 text-sm font-medium"
        onMouseLeave={() => setShowCategory(false)}
      >
        <Link to="/" className="mx-4 hover:text-green-700">Trang chủ</Link>
        <div 
          className="relative mx-4"
          onMouseEnter={() => setShowCategory(true)}
        >
          <span className="cursor-pointer hover:text-green-700">Danh mục</span>
          {showCategory && (
            <div 
              className="absolute top-full left-0 mt-2 bg-white border rounded-md shadow-lg p-3 w-48"
              onMouseEnter={() => setShowCategory(true)}
              onMouseLeave={() => setShowCategory(false)}
            >
              <Link to="/category/hoa-sinh-nhat" className="block py-1 hover:text-green-700">Hoa Sinh Nhật</Link>
              <Link to="/category/hoa-tang" className="block py-1 hover:text-green-700">Hoa Tặng</Link>
              <Link to="/category/hoa-cuoi" className="block py-1 hover:text-green-700">Hoa Cưới</Link>
            </div>
          )}
        </div>
        <Link to="/about" className="mx-4 hover:text-green-700">Giới thiệu</Link>
        <Link to="/contact" className="mx-4 hover:text-green-700">Liên hệ</Link>
      </nav>
    </header>
  );
};

export default HeaderBar;
